parameters.jsCode:
const raw = $input.item.json.message?.content
  ?? $input.item.json.choices?.[0]?.message?.content
  ?? $input.item.json.text
  ?? $input.item.json.content
  ?? '';

const asArray = (value) => Array.isArray(value) ? value : [];

let parsed;
try {
  const cleaned = String(raw).replace(/```json|```/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  // JSON parse 失敗時 fallback 到 urgency=low
  parsed = {
    urgency: 'low',
    lead_type: 'information_seeker',
    reason: 'AI 回應格式異常，已降級為 low',
    suggested_action: '請手動檢視此 lead',
    confirmed_data: [],
    inferred_data: [],
    missing_data: [{ field: 'all', label: '全部欄位', reason: 'AI 分類失敗，需業務手動確認' }],
    follow_up_questions: [],
    kpi_tracking_hint: 'AI 分類失敗，請業務盡速手動確認'
  };
}

return [{
  json: {
    urgency: parsed.urgency || 'low',
    lead_type: parsed.lead_type || 'information_seeker',
    reason: parsed.reason || '',
    suggested_action: parsed.suggested_action || '',
    confirmed_data: asArray(parsed.confirmed_data),
    inferred_data: asArray(parsed.inferred_data),
    missing_data: asArray(parsed.missing_data),
    follow_up_questions: asArray(parsed.follow_up_questions),
    kpi_tracking_hint: parsed.kpi_tracking_hint || '建議業務在 7 天內補完關鍵欄位',
    raw_ai_response: raw,
    parse_error: !parsed.urgency ? true : false
  }
}];

